files.content:
*** Settings ***
Library    Browser
Resource   locators.resource

*** Variables ***
${BASE_URL}             https://fabianofernandeseventos.com.br/
${HEADLESS}             ${True}
${BROWSER}              chromium
${VIEWPORT_WIDTH}       1280
${VIEWPORT_HEIGHT}      720
${MOBILE_WIDTH}         375
${MOBILE_HEIGHT}        812

*** Keywords ***
Abrir Navegador
    New Browser    browser=${BROWSER}    headless=${HEADLESS}
    New Context    viewport={'width': ${VIEWPORT_WIDTH}, 'height': ${VIEWPORT_HEIGHT}}
    New Page       ${BASE_URL}
    Wait For Load State    domcontentloaded

Fechar Navegador
    Close Browser

Ir Para Pagina Inicial
    Go To    ${BASE_URL}
    Wait For Load State    domcontentloaded
    Wait For Elements State    ${SECAO_INICIO}    visible

Configurar Viewport Desktop
    Set Viewport Size    ${VIEWPORT_WIDTH}    ${VIEWPORT_HEIGHT}

Configurar Viewport Mobile
    Set Viewport Size    ${MOBILE_WIDTH}    ${MOBILE_HEIGHT}

Clicar Link Menu
    [Arguments]    ${locator_menu}
    Wait For Elements State    ${locator_menu}    visible
    Click    ${locator_menu}

Verificar Secao Visivel
    [Arguments]    ${locator_secao}
    Scroll To Element    ${locator_secao}
    Wait For Elements State    ${locator_secao}    visible

Verificar Titulo Secao Visivel
    [Arguments]    ${locator_titulo}
    Wait For Elements State    ${locator_titulo}    visible

Verificar Texto Visivel Na Pagina
    [Arguments]    ${texto}
    Wait For Elements State    text=${texto}    visible

Verificar Atributo Href Contem
    [Arguments]    ${locator}    ${trecho_esperado}
    Wait For Elements State    ${locator}    visible
    ${href}=    Get Attribute    ${locator}    href
    Should Contain    ${href}    ${trecho_esperado}

Abrir Menu Mobile
    Wait For Elements State    ${BOTAO_MENU_MOBILE}    visible
    Click    ${BOTAO_MENU_MOBILE}
    Wait For Elements State    ${MENU_NAVEGACAO}    visible

Rolar Ate Secao
    [Arguments]    ${locator_secao}
    Scroll To Element    ${locator_secao}
    Wait For Elements State    ${locator_secao}    visible
